import { describe, it, before, after } from 'node:test';
import assert from 'node:assert/strict';
import request from 'supertest';
import { createApp } from '../index.js';
import { initDb, closeDb, createCard } from '../db/queries.js';

// в”Ђв”Ђ Subtask 1: Basic CRUD endpoints в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// Block A вЂ” GET /api/cards (empty DB)
describe('GET /api/cards', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('returns 200', async () => {
    const res = await request(app).get('/api/cards');
    assert.strictEqual(res.status, 200);
  });

  it('returns an array', async () => {
    const res = await request(app).get('/api/cards');
    assert.ok(Array.isArray(res.body));
  });

  it('returns empty array on empty DB', async () => {
    const res = await request(app).get('/api/cards');
    assert.deepStrictEqual(res.body, []);
  });
});

// Block B вЂ” POST /api/cards (fresh DB)
describe('POST /api/cards', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('returns 201 with valid title', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: 'New card' });
    assert.strictEqual(res.status, 201);
  });

  it('returned body has id, title, column, position, created_at fields', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: 'Shape test' });
    assert.ok(res.body.id, 'expected id field');
    assert.strictEqual(res.body.title, 'Shape test');
    assert.ok(res.body.column, 'expected column field');
    assert.ok(typeof res.body.position === 'number', 'expected numeric position');
    assert.ok(res.body.created_at, 'expected created_at field');
  });

  it('returned body.comments is an empty array', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: 'Comments test' });
    assert.deepStrictEqual(res.body.comments, []);
  });
});

// Block C вЂ” PATCH and DELETE /api/cards/:id (pre-seeded DB)
// NOTE: PATCH tests MUST run before DELETE tests (they share the same seeded card)
describe('PATCH and DELETE /api/cards/:id basic', () => {
  let app, existingCard;
  before(() => {
    initDb(':memory:');
    app = createApp();
    existingCard = createCard({ title: 'Seed card' });
  });
  after(() => closeDb());

  it('PATCH returns 200 with updated card', async () => {
    const res = await request(app)
      .patch(`/api/cards/${existingCard.id}`)
      .send({ title: 'Updated title' });
    assert.strictEqual(res.status, 200);
  });

  it('PATCH updated card reflects new title in response', async () => {
    const res = await request(app)
      .patch(`/api/cards/${existingCard.id}`)
      .send({ title: 'Patched title' });
    assert.strictEqual(res.body.title, 'Patched title');
  });

  it('DELETE returns 204', async () => {
    const res = await request(app)
      .delete(`/api/cards/${existingCard.id}`);
    assert.strictEqual(res.status, 204);
  });

  it('DELETE response body is empty', async () => {
    // Re-create a card to delete (previous test already deleted existingCard)
    const card2 = createCard({ title: 'Card to delete' });
    const res = await request(app)
      .delete(`/api/cards/${card2.id}`);
    assert.strictEqual(res.status, 204);
    assert.strictEqual(res.text, '');
  });
});

// в”Ђв”Ђ Subtask 2: Input validation в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// Block D вЂ” POST /api/cards validation (fresh DB)
describe('POST /api/cards validation', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('POST without body returns 400', async () => {
    const res = await request(app).post('/api/cards');
    assert.strictEqual(res.status, 400);
  });

  it('POST with missing title field returns 400', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ assignee: 'Alice' });
    assert.strictEqual(res.status, 400);
  });

  it('POST with empty string title returns 400', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: '' });
    assert.strictEqual(res.status, 400);
  });

  it('POST with whitespace-only title returns 400', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: '   ' });
    assert.strictEqual(res.status, 400);
  });

  it('400 response body has error string field', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({});
    assert.strictEqual(typeof res.body.error, 'string');
  });
});

// в”Ђв”Ђ Subtask 3: DB integration в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// Block E вЂ” GET /api/cards DB integration (pre-seeded DB)
describe('GET /api/cards DB integration', () => {
  let app;
  before(() => {
    initDb(':memory:');
    app = createApp();
    createCard({ title: 'Pre-seeded card' });
  });
  after(() => closeDb());

  it('returns the pre-seeded card', async () => {
    const res = await request(app).get('/api/cards');
    assert.strictEqual(res.body.length, 1);
    assert.strictEqual(res.body[0].title, 'Pre-seeded card');
  });

  it('each card has a comments array', async () => {
    const res = await request(app).get('/api/cards');
    for (const card of res.body) {
      assert.ok(Array.isArray(card.comments), `card ${card.id} missing comments array`);
    }
  });
});

// Block F вЂ” POST /api/cards DB persistence (fresh DB)
describe('POST /api/cards DB persistence', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('POST-created card appears in subsequent GET', async () => {
    await request(app).post('/api/cards').send({ title: 'Persisted card' });
    const res = await request(app).get('/api/cards');
    assert.ok(res.body.some(c => c.title === 'Persisted card'));
  });

  it('POST-created card has correct title in response', async () => {
    const res = await request(app)
      .post('/api/cards')
      .send({ title: 'Title check' });
    assert.strictEqual(res.body.title, 'Title check');
  });
});

// Block G вЂ” PATCH/DELETE 404 for unknown IDs (fresh DB)
describe('PATCH and DELETE 404 for unknown IDs', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('PATCH /api/cards/nonexistent-id returns 404', async () => {
    const res = await request(app)
      .patch('/api/cards/does-not-exist')
      .send({ title: 'Updated' });
    assert.strictEqual(res.status, 404);
  });

  it('DELETE /api/cards/nonexistent-id returns 404', async () => {
    const res = await request(app)
      .delete('/api/cards/does-not-exist');
    assert.strictEqual(res.status, 404);
  });
});

// Block H вЂ” PATCH/DELETE happy path (pre-seeded DB)
// NOTE: PATCH test runs before DELETE test (shares the same seeded card)
describe('PATCH and DELETE happy path', () => {
  let app, card;
  before(() => {
    initDb(':memory:');
    app = createApp();
    card = createCard({ title: 'Original title' });
  });
  after(() => closeDb());

  it('PATCH updates title and response body has new title', async () => {
    const res = await request(app)
      .patch(`/api/cards/${card.id}`)
      .send({ title: 'Updated title' });
    assert.strictEqual(res.status, 200);
    assert.strictEqual(res.body.title, 'Updated title');
  });

  it('DELETE removes card; subsequent GET does not include it', async () => {
    await request(app).delete(`/api/cards/${card.id}`);
    const res = await request(app).get('/api/cards');
    assert.ok(!res.body.some(c => c.id === card.id), 'deleted card should not appear in GET');
  });
});

// в”Ђв”Ђ Subtask 4: Error response format в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

// Block I вЂ” Error response format (fresh DB)
describe('Error response format', () => {
  let app;
  before(() => { initDb(':memory:'); app = createApp(); });
  after(() => closeDb());

  it('PATCH unknown ID returns Content-Type application/json', async () => {
    const res = await request(app)
      .patch('/api/cards/unknown-id')
      .send({ title: 'x' });
    assert.ok(
      res.headers['content-type']?.includes('application/json'),
      `expected application/json, got ${res.headers['content-type']}`
    );
  });

  it('DELETE unknown ID returns Content-Type application/json', async () => {
    const res = await request(app).delete('/api/cards/unknown-id');
    assert.ok(
      res.headers['content-type']?.includes('application/json'),
      `expected application/json, got ${res.headers['content-type']}`
    );
  });

  it('404 response body has error string field', async () => {
    const res = await request(app).patch('/api/cards/unknown-id').send({ title: 'x' });
    assert.strictEqual(typeof res.body.error, 'string');
  });

  it('400 response body has error string field', async () => {
    const res = await request(app).post('/api/cards').send({});
    assert.strictEqual(res.status, 400);
    assert.strictEqual(typeof res.body.error, 'string');
  });
});

